SELECT COALESCE(SUM(pay_amount), 0)
FROM cb_order
WHERE deleted = 0
  AND status IN (5, 6)
AND create_time >= #{from}
AND create_time <  #{to}

SELECT COALESCE(SUM(platform_income), 0)
FROM cb_order
WHERE deleted = 0
  AND status IN (5, 6)
AND create_time >= #{from}
AND create_time <  #{to}

SELECT COUNT(*)
FROM cb_order
WHERE deleted = 0
AND create_time >= #{from}      
AND create_time <  #{to}        
AND merchant_id  =   #{merchantId}
